"use client";

import { motion } from "framer-motion";

const steps = [
  {
    number: "01",
    title: "Konsultasi",
    description:
      "Kami mendengarkan ide, keinginan, dan ekspektasi Anda secara mendetail. Dari tema, budget, hingga jumlah tamu — semuanya kita bahas bersama.",
  },
  {
    number: "02",
    title: "Perencanaan & Konsep",
    description:
      "Tim kreatif kami merancang konsep acara yang sesuai dengan visi Anda — termasuk desain venue, rundown, dekorasi, dan kebutuhan teknis.",
  },
  {
    number: "03",
    title: "Persiapan & Koordinasi",
    description:
      "Kami mengurus semua vendor, perizinan, dan detail logistik. Anda tinggal duduk santai sementara kami bekerja di balik layar.",
  },
  {
    number: "04",
    title: "Hari-H & Eksekusi",
    description:
      "Tim kami hadir di lapangan memastikan setiap momen berjalan lancar dan sesuai rencana — dari awal hingga akhir.",
  },
];

export default function Process() {
  return (
    <section className="py-24 md:py-32 bg-[#fef0f5]">
      <div className="max-w-[1400px] mx-auto px-6 md:px-12">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-12 mb-20">
          <div className="md:col-span-5">
            <motion.p
              initial={{ opacity: 0 }}
              whileInView={{ opacity: 1 }}
              viewport={{ once: true }}
              className="text-[13px] uppercase tracking-[0.2em] font-medium text-stone-400 mb-4"
            >
              How we work
            </motion.p>
            <motion.h2
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: 0.1 }}
              className="text-3xl md:text-4xl font-semibold tracking-tight text-stone-900 leading-tight"
            >
              Dari ide menjadi
              <br />
              kenyataan.
            </motion.h2>
          </div>
          <div className="md:col-span-6 md:col-start-7 flex items-end">
            <motion.p
              initial={{ opacity: 0 }}
              whileInView={{ opacity: 1 }}
              viewport={{ once: true }}
              transition={{ delay: 0.2 }}
              className="text-stone-500 text-lg leading-relaxed"
            >
              Proses kami dirancang agar Anda bisa menikmati perjalanan
              merencanakan acara — tanpa stres, tanpa ribet.
            </motion.p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {steps.map((step, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.5 }}
              className="group"
            >
              <div className="text-5xl font-bold text-[#fdbcd6] mb-6 group-hover:text-stone-900 transition-colors duration-500">
                {step.number}
              </div>
              <h3 className="text-xl font-semibold text-stone-900 mb-4">
                {step.title}
              </h3>
              <p className="text-stone-500 leading-relaxed text-[15px]">
                {step.description}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
